"use client";

import Link from "next/link";
import { Copy, ExternalLink, ShieldCheck } from "lucide-react";
import type { EvidenceCard } from "@/lib/types";

export function CardClient({ initialCard, reportId }: { initialCard: EvidenceCard | null; reportId: string }) {
  if (!initialCard) {
    return (
      <main className="app-shell compact">
        <section className="panel empty-state">
          <h1>没有找到这张证据卡</h1>
          <Link className="primary-link" href="/" data-empty-cta="回到投前体检台">回到投前体检台</Link>
        </section>
      </main>
    );
  }

  return (
    <main className="app-shell" data-visual-lane="operational-dashboard / blueprint-lab 混合。" data-hero-composition="evidence-receipt" data-testid="screen-card">
      <header className="topbar">
        <Link className="brand-lockup link-reset" href={`/result/${reportId}`}>
          <div className="brand-mark">体</div>
          <div>
            <h1>求职证据卡</h1>
            <p>扫码后只读查看，不暴露编辑入口</p>
          </div>
        </Link>
        <div className="boundary-note" data-testid="readonly-banner">只读查看模式</div>
      </header>
      <section className="card-layout">
        <article className="evidence-card" data-testid="evidence-card">
          <div className="card-heading">
            <span className="status-pill green" data-testid="card-traffic-light">{initialCard.trafficLight === "green" ? "可以投" : "先补证据"}</span>
            <span>生成时间：{new Date(initialCard.generatedAt).toLocaleString("zh-CN")}</span>
          </div>
          <div className="card-score-row">
            <div>
              <h2>{initialCard.targetRole}</h2>
              <p>我的投前体检结果</p>
            </div>
            <strong data-testid="card-score">{initialCard.score}<small>分</small></strong>
          </div>
          <section>
            <h3>已有证据</h3>
            <div className="card-list" data-testid="card-proven-list">
              {initialCard.provenPoints.map((item) => <span key={item}>{item}</span>)}
            </div>
          </section>
          <section>
            <h3>还需补充</h3>
            <div className="card-list muted" data-testid="card-gap-list">
              {initialCard.weakPoints.map((item) => <span key={item}>{item}</span>)}
            </div>
          </section>
          <section className="next-action" data-testid="card-next-action">
            <h3>下一步只做这一件事</h3>
            <p>{initialCard.nextAction}</p>
          </section>
          <p className="card-boundary" data-testid="card-boundary-note">{initialCard.boundaryText}</p>
        </article>
        <aside className="panel share-panel">
          <div className="qr-box" data-testid="card-qrcode" aria-label="扫码查看求职证据卡" />
          <button className="primary-button wide min-h-11 min-w-11" type="button" data-testid="copy-card-link-button" data-next-step-cta="复制分享链接" onClick={() => navigator.clipboard?.writeText(location.href)}>
            <Copy size={18} />复制分享链接
          </button>
          <Link className="secondary-link" href={`/trace/${reportId}`}><ExternalLink size={18} />查看智能体轨迹</Link>
          <Link className="secondary-link" href={`/result/${reportId}`}>返回体检结果</Link>
        </aside>
      </section>
    </main>
  );
}
